package com.hiliving.admin.dashboard;
import com.hiliving.api.ApiResponse;import com.hiliving.catalog.product.persistence.*;import com.hiliving.catalog.category.persistence.CategoryRepository;import com.hiliving.catalog.brand.persistence.BrandRepository;import com.hiliving.identity.user.persistence.UserRepository;import com.hiliving.content.banner.BannerRepository;import com.hiliving.content.news.NewsRepository;import org.springframework.web.bind.annotation.*;
@RestController@RequestMapping("/api/v1/admin/dashboard")public class AdminDashboardController{private final ProductRepository products;private final CategoryRepository categories;private final BrandRepository brands;private final UserRepository users;private final BannerRepository banners;private final NewsRepository news;public AdminDashboardController(ProductRepository products,CategoryRepository categories,BrandRepository brands,UserRepository users,BannerRepository banners,NewsRepository news){this.products=products;this.categories=categories;this.brands=brands;this.users=users;this.banners=banners;this.news=news;}@GetMapping public ApiResponse<AdminDashboardResponse> get(){return ApiResponse.of(new AdminDashboardResponse(products.count(),products.countByStatus(ProductStatus.ACTIVE),products.countByStatus(ProductStatus.DRAFT),products.countByStatus(ProductStatus.ARCHIVED),categories.count(),brands.count(),users.count(),banners.countByActiveTrue(),news.countByPublishedTrue()));}}
